const { sources } = $json;
if (!Array.isArray(sources)) return { error: 'sources array required' };
return { sources: sources.map((s, i) => ({ id: `source-${i + 1}`, ...s, status: 'pending' })) };

const source = $json;
const { type, target, params } = source;
const results = {
  'weather': { temperature: 22, humidity: 65, conditions: 'partly_cloudy', source: 'openweather' },
  'news': { headlines: ['Local mining output up 12%', 'New safety regulations announced'], source: 'newsapi' },
  'stocks': { indices: { asx200: 7821.5, mining_sector: 3.2 }, source: 'marketstack' },
  'database': { query_result: 'SELECT returned 42 rows', source: 'postgres' },
  'file_system': { files: ['report.pdf', 'data.csv'], source: 'local' }
};
const result = results[type] || { error: `Unknown source type: ${type}`, source: type };
return { ...source, status: 'complete', data: result, fetched_at: new Date().toISOString() };

const outputs = $input.all();
const completed = outputs.filter(o => o.status === 'complete');
const errors = outputs.filter(o => o.data?.error);
return {
  total_sources: outputs.length,
  completed: completed.length,
  errors: errors.length,
  results: completed.map(o => ({
    id: o.id,
    type: o.type,
    data: o.data,
    elapsed_ms: o.elapsed_ms
  })),
  parallel: true,
  summary: `Fetched ${completed.length}/${outputs.length} sources in parallel (${errors.length} errors)`
};
